use std::collections::VecDeque;

struct Session<T: Clone>
{
    _marker: std::marker::PhantomData<T>,
    queue: VecDeque<T>,
}

impl<T: Clone>
Session<T>
{
    fn new(initial_data: Vec<T>)
    -> Self
    {
        Session { 
            _marker: std::marker::PhantomData,
            queue: initial_data.into()
        }
    }

    fn consume(&mut self)
    -> Option<T>
    {
        self.queue.pop_front()
    }

    fn append(&mut self, data: T)
    {
        self.queue.push_back(data);
    }
}

fn main()
{
    let mut session_a = Session::new(vec![10i32, 20i32]);
    println!("Initial state: {:?}", session_a.consume());

    session_a.append(30);
    println!("After append: {:?}", session_a.consume());

    let data_c = 40i32;
    session_a.append(data_c);
    println!("After second append: {:?}", session_a.consume());

    println!("Final state check: {:?}", session_a.consume());
}

use std::collections::VecDeque;

struct StateMachine {
    log: VecDeque<String>,
}

impl StateMachine {
    fn new() -> Self {
        StateMachine { log: VecDeque::new() }
    }

    fn append(&mut self, entry: String) -> Result<(), &'static str> {
        if entry.is_empty() {
            return Err("Cannot process empty message.");
        }
        self.log.push_back(entry);
        Ok(())
    }

    fn get_last(&self) -> Option<&str> {
        self.log.back().map(|s| s.as_str())
    }
}

struct ConsensusChannel {
    state: StateMachine,
}

impl ConsensusChannel {
    fn new() -> Self {
        ConsensusChannel { state: StateMachine::new() }
    }

    fn send_heartbeat(&mut self, node_id: &str) -> Result<(), &'static str> {
        self.state.append(format!("Heartbeat from {}", node_id))?;
        Ok(())
    }

    fn process_vote(&mut self, candidate_id: &str, term: u64) -> Result<(), &'static str> {
        if term == 0 {
            return Err("Invalid Raft term.");
        }
        self.state.append(format!("Vote processed for {} in Term {}", candidate_id, term))?;
        Ok(())
    }
}

use std::collections::HashMap;

struct LayerInfo {
    name: String,
    size_bytes: u64,
}

fn analyze_layers(initial_map: HashMap<String, u64>) -> Result<Vec<LayerInfo>, String> {
    let mut processed_data = Vec::new();
    let mut current_sizes = initial_map;

    for (layer_name, &size) in current_sizes.iter() {
        if size == 0 {
            return Err(format!("Encountered a zero-sized layer for {}. Cannot process.", layer_name));
        }
        let info = LayerInfo {
            name: layer_name.clone(),
            size_bytes: size,
        };
        processed_data.push(info);
    }

    if processed_data.is_empty() {
        return Err("No layers were provided to analyze.".to_string());
    }

    Ok(processed_data)
}

fn main() {
    let mut input_map = HashMap::new();
    input_map.insert("base".to_string(), 1024 * 5);
    input_map.insert("app_code".to_string(), 512 * 1024);
    input_map.insert("config".to_string(), 256); 

    match analyze_layers(input_map) {
        Ok(layers) => {
            println!("Successfully analyzed {} layers:", layers.len());
            for layer in layers {
                println!("  Name: {}, Size: {}", layer.name, layer.size_bytes);
            }
        },
        Err(e) => {
            eprintln!("Analysis Failed: {}", e);
        }
    }

    let mut bad_map = HashMap::new();
    bad_map.insert("empty_layer".to_string(), 0);
    match analyze_layers(bad_map) {
        Ok(_) => {}, 
        Err(e) => println!("Caught expected error: {}", e)
    }
}

use std::collections::HashMap;
use std::sync::{Arc, Mutex};

struct RateLimiter {
    request_counts: Arc<Mutex<HashMap<String, Vec<i64>>>>,
    window_size_seconds: i64,
} 

impl RateLimiter {
    fn new(window_size: i64) -> Self {
        RateLimiter {
            request_counts: Arc::new(Mutex::new(HashMap::new())),
            window_size_seconds: window_size,
        }
    }

    fn check(&self, client_ip: &str) -> bool {
        let mut counts = self.request_counts.lock().unwrap();
        let current_time = std::time::SystemTime::now().duration_since(std::time::SystemTime::UNIX_EPOCH).unwrap().as_secs() as i64;
        let entry = counts.entry(client_ip.to_string()).or_insert_with(Vec::new);
        let timestamps: &mut Vec<i64> = entry;

        timestamps.retain(|&ts| current_time - ts < self.window_size_seconds);

        if timestamps.len() >= 5 {
            return false;
        }

        timestamps.push(current_time);
        true
    }
}

async fn rate_limited_handler(limiter: Arc<RateLimiter>) -> &'static str {
    let ip = "127.0.0.1"; 

    if limiter.check(ip) {
        "Access granted! This request was processed."
    } else {
        "Too many requests. Please try again later."
    }
}

#[tokio::main]
async fn main() {
    let limiter = Arc::new(RateLimiter::new(60));
    println!("--- First Request ---");
    let result1 = rate_limited_handler(Arc::clone(&limiter)).await;
    println!("Result: {}", result1);

    tokio::time::sleep(std::time::Duration::from_millis(50)).await;
    println!("n--- Second Request ---");
    let result2 = rate_limited_handler(Arc::clone(&limiter)).await;
    println!("Result: {}", result2);
}

use std::collections::VecDeque;

struct StateTracker<T>
{
    queue: VecDeque<T>,
}

impl<T> StateTracker<T>
{
    fn new(initial_state: T) -> Self
    {
        StateTracker { queue: VecDeque::from([initial_state]) }
    }

    fn consume(&mut self) -> Option<T>
    {
        self.queue.pop_front()
    }

    fn add(&mut self, item: T)
    {
        self.queue.push_back(item);
    }

    fn is_empty(&self) -> bool
    {
        self.queue.is_empty()
    }
}

fn process_step<T: std::fmt::Debug>(tracker: &mut StateTracker<T>) -> Option<T>
{
    println!("Processing step...");
    tracker.consume()
}

fn finalize_session<T: std::fmt::Debug>(tracker: &mut StateTracker<T>) -> T
{
    println!("Finalizing session...");
    match tracker.consume() {
        Some(final_item) => final_item,
        None => panic!("Cannot finalize, state queue is empty."),
    }
}

fn main() -> std::result::Result<(), Box<dyn std::error::Error>>
{
    let mut session_state = StateTracker::new(10);

    session_state.add(20);

    match process_step(&mut session_state) {
        Some(val) => println!("Consumed value: {}", val),
        None => unreachable!(),
    }

    session_state.add(30);

    let final_result = finalize_session(&mut session_state);
    println!("Final result successfully extracted: {}", final_result);

    Ok(())
}
